steps.script:
GameState.set_edition(11)
var U = GameState.state["units"]
var mine = {"U_FD_TANK_A": true, "U_FD_BOYZ": true, "U_FD_TARGET_A": true, "U_FD_TARGET_C": true}
for uid in U.keys():
	if mine.has(uid):
		continue
	for m in U[uid].get("models", []):
		if m.get("position") != null:
			m["position"] = {"x": 12000.0, "y": 12000.0}
var boyz_models = []
for i in range(10):
	boyz_models.append({"id": "m%d" % (i + 1), "wounds": 1, "current_wounds": 1, "base_mm": 32, "position": null, "alive": true, "status_effects": []})
U.merge({"U_FD_TANK_A": {"id": "U_FD_TANK_A", "owner": 1, "status": 2, "flags": {}, "meta": {"name": "FD Wagon A", "keywords": ["VEHICLE", "TRANSPORT"], "stats": {"move": 10, "toughness": 10, "save": 3, "wounds": 16, "leadership": 6, "objective_control": 5}, "weapons": [{"name": "Big shoota", "type": "Ranged", "range": "36", "attacks": "3", "ballistic_skill": "5", "strength": "5", "ap": "0", "damage": "1", "special_rules": ""}]}, "transport_data": {"firing_deck": 11, "capacity": 22, "capacity_multipliers": {"MEGA ARMOUR": 2, "JUMP PACK": 2}, "embarked_units": ["U_FD_BOYZ"]}, "models": [{"id": "t0", "alive": true, "position": {"x": 200, "y": 400}, "base_mm": 170, "wounds": 16, "current_wounds": 16}]}, "U_FD_BOYZ": {"id": "U_FD_BOYZ", "owner": 1, "status": 2, "flags": {}, "embarked_in": "U_FD_TANK_A", "meta": {"name": "Boyz", "keywords": ["INFANTRY", "ORKS", "MOB"], "stats": {"move": 6, "toughness": 5, "save": 5, "wounds": 1, "leadership": 7, "objective_control": 2}, "weapons": [{"name": "Slugga", "type": "Ranged", "range": "12", "attacks": "1", "ballistic_skill": "5", "strength": "4", "ap": "0", "damage": "1", "special_rules": "pistol", "abilities": [{"id": "pistol"}]}, {"name": "Choppa", "type": "Melee", "range": "Melee", "attacks": "3", "weapon_skill": "3", "strength": "4", "ap": "-1", "damage": "1"}]}, "models": boyz_models}, "U_FD_TARGET_A": {"id": "U_FD_TARGET_A", "owner": 2, "status": 2, "flags": {}, "meta": {"name": "Target A", "keywords": ["INFANTRY"], "stats": {"move": 6, "toughness": 4, "save": 4, "wounds": 2, "leadership": 6, "objective_control": 2}, "weapons": []}, "models": [{"id": "e0", "alive": true, "position": {"x": 650, "y": 400}, "base_mm": 32, "wounds": 2, "current_wounds": 2}]}, "U_FD_TARGET_C": {"id": "U_FD_TARGET_C", "owner": 2, "status": 2, "flags": {}, "meta": {"name": "Target C", "keywords": ["INFANTRY"], "stats": {"move": 6, "toughness": 4, "save": 4, "wounds": 2, "leadership": 6, "objective_control": 2}, "weapons": []}, "models": [{"id": "e0", "alive": true, "position": {"x": 200, "y": 800}, "base_mm": 32, "wounds": 2, "current_wounds": 2}]}}, true)
return U.has("U_FD_TANK_A") and U.has("U_FD_BOYZ") and U.has("U_FD_TARGET_A") and U.has("U_FD_TARGET_C")

var root = tree.current_scene.get_node("ShootingController").weapon_tree.get_root()
var n = 0
var c = root.get_first_child()
while c:
	n += 1
	c = c.get_next()
return n

var root = tree.current_scene.get_node("ShootingController").weapon_tree.get_root()
var slug_rows = 0
var c = root.get_first_child()
while c:
	if str(c.get_metadata(0)).begins_with("slugga"):
		slug_rows += 1
	c = c.get_next()
return slug_rows

var root = tree.current_scene.get_node("ShootingController").weapon_tree.get_root()
var c = root.get_first_child()
while c:
	if str(c.get_metadata(0)).begins_with("slugga"):
		return c.get_text(0).contains("10")
	c = c.get_next()
return false

var wt = tree.current_scene.get_node("ShootingController").weapon_tree
var c = wt.get_root().get_first_child()
while c:
	if str(c.get_metadata(0)).begins_with("slugga"):
		c.select(0)
		break
	c = c.get_next()
return wt.get_selected() != null and str(wt.get_selected().get_metadata(0)).begins_with("slugga")

var pa = tree.current_scene.get_node("ShootingController").current_phase.pending_assignments
var t = 0
for x in pa:
	if str(x.get("weapon_id", "")).begins_with("slugga"):
		t += x.get("model_ids", []).size()
return t

var pa = tree.current_scene.get_node("ShootingController").current_phase.pending_assignments
for x in pa:
	if str(x.get("weapon_id", "")).begins_with("slugga"):
		return str(x.get("target_unit_id", ""))
return "none"

var wt = tree.current_scene.get_node("ShootingController").weapon_tree
var c = wt.get_root().get_first_child()
while c:
	if str(c.get_metadata(0)).begins_with("slugga"):
		c.select(0)
		break
	c = c.get_next()
return true

var picker = tree.current_scene.get_node("ShootingController").find_child("SplitFirePicker", true, false)
var spin = picker.find_child("SplitFireSpin", true, false)
spin.value = 4
return int(spin.value)

var pa = tree.current_scene.get_node("ShootingController").current_phase.pending_assignments
var n = 0
for x in pa:
	if str(x.get("weapon_id", "")).begins_with("slugga"):
		n += 1
return n

var pa = tree.current_scene.get_node("ShootingController").current_phase.pending_assignments
var a = 0
for x in pa:
	if str(x.get("weapon_id", "")).begins_with("slugga") and x.get("target_unit_id", "") == "U_FD_TARGET_A":
		a = x.get("model_ids", []).size()
return a

var pa = tree.current_scene.get_node("ShootingController").current_phase.pending_assignments
var b = 0
for x in pa:
	if str(x.get("weapon_id", "")).begins_with("slugga") and x.get("target_unit_id", "") == "U_FD_TARGET_C":
		b = x.get("model_ids", []).size()
return b
